import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { X, Loader2, CheckCircle, Banknote, ArrowRight } from 'lucide-react';
import './WalletActions.css';

export default function Withdraw() {
  const navigate = useNavigate();
  
  const [amount, setAmount] = useState('');
  const [account, setAccount] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [withdrawAmount, setWithdrawAmount] = useState(0);

  useEffect(() => {
    const handleEsc = (e) => e.key === 'Escape' && navigate('/wallet');
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [navigate]);

  const handleWithdraw = async () => {
    setError('');
    const num = parseFloat(amount);
    if (!amount || isNaN(num) || num <= 0) return setError('Enter a valid amount');
    if (!account.trim()) return setError('Enter UPI or Bank details');
    if (num < 50) return setError('Minimum withdrawal is ₹50');

    setLoading(true);
    try {
      // 🔥 Replace with backend API
      await new Promise(res => setTimeout(res, 1500));
      setWithdrawAmount(num);
      setSuccess(true);
    } catch {
      setError('Withdrawal failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => navigate('/wallet');

  if (success) {
    return (
      <div className="wallet-modal-overlay" onClick={handleClose}>
        <div className="wallet-modal-card" onClick={e => e.stopPropagation()}>
          <button onClick={handleClose} className="modal-close-btn" aria-label="Close"><X size={20} /></button>
          <div className="success-content">
            <div className="success-icon"><CheckCircle size={48} /></div>
            <h3>₹{withdrawAmount.toFixed(2)} Requested!</h3>
            <p className="success-msg">Your withdrawal is being processed. Funds will be credited soon.</p>
            <div className="success-details">
              <div className="detail-row"><span>Account</span><strong>{account}</strong></div>
              <div className="detail-row"><span>Time</span><strong>{new Date().toLocaleTimeString()}</strong></div>
            </div>
            <div className="success-actions">
              <button className="primary-btn" onClick={handleClose}>
                <span>Back to Wallet</span><ArrowRight size={18} />
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="wallet-modal-overlay" onClick={handleClose}>
      <div className="wallet-modal-card" onClick={e => e.stopPropagation()}>
        <button onClick={handleClose} className="modal-close-btn" aria-label="Close"><X size={20} /></button>
        <h2 className="modal-title">Withdraw Money</h2>
        
        <div className="modal-form">
          <div className="form-section">
            <label>Amount to Withdraw</label>
            <div className="amount-input-wrap">
              <span className="currency-sym">₹</span>
              <input type="number" placeholder="0.00" value={amount} onChange={(e) => setAmount(e.target.value)} min="50" step="0.01" />
            </div>
            {error && <p className="error-msg" role="alert">{error}</p>}
          </div>

          <div className="form-section">
            <label>UPI ID / Bank Account</label>
            <input 
              type="text" 
              placeholder="e.g. username@upi or Bank A/c No." 
              value={account} 
              onChange={(e) => setAccount(e.target.value)} 
              className="text-input"
            />
          </div>

          {amount && parseFloat(amount) >= 50 && (
            <div className="summary-box">
              <div className="sum-row"><span>Processing Fee</span><strong className="free">₹0</strong></div>
              <div className="sum-row total"><span>You will receive</span><strong>₹{parseFloat(amount).toFixed(2)}</strong></div>
            </div>
          )}

          <button 
            className="primary-btn" 
            onClick={handleWithdraw} 
            disabled={loading || !amount || parseFloat(amount) < 50 || !account}
          >
            {loading ? (
              <><Loader2 className="spin" size={18} /> Processing...</>
            ) : (
              <><span>Withdraw ₹{amount ? parseFloat(amount).toFixed(2) : '0.00'}</span><Banknote size={18} /></>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}
